void zobrist_init(void) {
    rand_state = 1070372ull;
    for (int p = 0; p < 12; p++)
        for (int sq = 0; sq < 64; sq++)
            ZobristPieces[p][sq] = rand64();
    for (int i = 0; i < 16; i++)
        ZobristCastling[i] = rand64();
    for (int sq = 0; sq < 64; sq++)
        ZobristEP[sq] = rand64();
    ZobristSide = rand64();

    /* Castling rights mask: when a piece moves from/to a square, AND rights with this */
    for (int sq = 0; sq < 64; sq++)
        CastlingRightsMask[sq] = ALL_CASTLING;
    CastlingRightsMask[A1] &= ~WHITE_OOO;
    CastlingRightsMask[H1] &= ~WHITE_OO;
    CastlingRightsMask[E1] &= ~(WHITE_OO | WHITE_OOO);
    CastlingRightsMask[A8] &= ~BLACK_OOO;
    CastlingRightsMask[H8] &= ~BLACK_OO;
    CastlingRightsMask[E8] &= ~(BLACK_OO | BLACK_OOO);
}

static void init_zobrist(void) {
    uint64_t seed = 0x123456789abcdef0ULL;

    for (int piece = 0; piece < 13; ++piece) {
        for (int sq = 0; sq < 64; ++sq) {
            g_zob_piece[piece][sq] = splitmix64_next(&seed);
        }
    }
    for (int i = 0; i < 16; ++i) {
        g_zob_castling[i] = splitmix64_next(&seed);
    }
    for (int i = 0; i < 8; ++i) {
        g_zob_ep[i] = splitmix64_next(&seed);
    }
    g_zob_side = splitmix64_next(&seed);
}

void TranspositionTable::resize(size_t mb) {
    delete[] table_;
    size_ = (mb * 1024 * 1024) / sizeof(TTEntry);
    // Round down to power of 2 for fast modulo
    size_t s = 1;
    while (s * 2 <= size_) s *= 2;
    size_ = s;
    table_ = new TTEntry[size_];
    clear();
}

void TranspositionTable::resize_mb(int mb) {
  const size_t bytes = static_cast<size_t>(mb) * 1024ULL * 1024ULL;
  const size_t n = bytes / sizeof(TTBucket);
  table_.assign(n ? n : 1, TTBucket{});
  generation_ = 0;
}

pub fn make_null_move(&mut self) {
    use crate::zobrist::zobrist;

    let z = zobrist();

    let undo = crate::board::UndoInfo {
        castling: self.castling,
        ep_square: self.ep_square,
        halfmove: self.halfmove,
        captured: None,
        hash: self.hash,
        pawn_hash: self.pawn_hash,
        mv: Move::NONE,
        mg_pst: self.mg_pst,
        eg_pst: self.eg_pst,
        phase: self.phase,
    };
    self.undo_stack.push(undo);

    if self.ep_square != Square::NONE {
        self.hash ^= z.en_passant(self.ep_square.file());
        self.ep_square = Square::NONE;
    }

    self.side = !self.side;
    self.hash ^= z.side();
    self.halfmove = 0;
    self.history.push(self.hash);
}

pub fn search(&mut self, params: GoParams) -> SearchResult {
    let legal_moves: Vec<ChessMove> = MoveGen::new_legal(&self.board).collect();
    if legal_moves.is_empty() {
        return SearchResult {
            best_move: None,
            score_cp: 0,
            depth: 0,
            nodes: 0,
            elapsed: Duration::ZERO,
        };
    }

    if let Some(book_move) = opening_book_move(&self.board) {
        if legal_moves.contains(&book_move) {
            return SearchResult {
                best_move: Some(book_move),
                score_cp: evaluate(&self.board),
                depth: 0,
                nodes: 0,
                elapsed: Duration::ZERO,
            };
        }
    }

    decay_history(&mut self.history);
    self.tt.start_search();

    let max_depth = match params.depth {
        Some(depth) => depth.clamp(1, MAX_DEPTH),
        None => {
            if params.movetime.is_some() || params.wtime.is_some() || params.btime.is_some() {
                MAX_DEPTH
            } else {
                DEFAULT_DEPTH
            }
        }
    };
    let deadline = compute_deadline(params, self.board.side_to_move());
    let mut killers = [[None; 2]; MAX_PLY];
    let mut search = Search::new(deadline, &mut self.tt, &mut self.history, &mut killers);

    let mut best_move = legal_moves[0];
    let mut best_score = evaluate(&self.board);
    let mut reached_depth = 0;

    for depth in 1..=max_depth {
        if search.out_of_time() {
            break;
        }

        let (score, depth_move, completed) =
            search.search_root(&self.board, depth as i32, &legal_moves, -INF, INF);
        if !completed {
            break;
        }

        reached_depth = depth;
        best_move = depth_move;
        best_score = score;
    }

    SearchResult {
        best_move: Some(best_move),
        score_cp: best_score,
        depth: reached_depth,
        nodes: search.nodes,
        elapsed: search.start.elapsed(),
    }
}

def repetition_history_hashes(board: chess.Board) -> list[int]:
    """Position hashes since the last irreversible move, excluding current node."""
    work = chess.Board()
    seq: list[int] = [int(chess.polyglot.zobrist_hash(work))]
    for move in board.move_stack:
        irreversible = work.is_irreversible(move)
        work.push(move)
        h = int(chess.polyglot.zobrist_hash(work))
        if irreversible:
            seq = [h]
        else:
            seq.append(h)
    return seq[:-1] if len(seq) > 1 else []

public TranspositionTable(int megabytes) {
    if (megabytes <= 0) {
        megabytes = 1;
    }

    long budgetBytes = megabytes * 1024L * 1024L;
    int entryBytes = Long.BYTES + Integer.BYTES + Integer.BYTES + 1 + Integer.BYTES;

    int size = 1;
    while ((long) size * entryBytes * 2L <= budgetBytes) {
        size <<= 1;
    }

    this.keys = new long[size];
    this.depths = new int[size];
    this.scores = new int[size];
    this.bounds = new byte[size];
    this.packedMoves = new int[size];
    this.mask = size - 1;
}

public TranspositionTable(int sizeInMB) {
    int entries = (sizeInMB * 1024 * 1024) / 16; // 16 bytes per entry (key + data)
    // Round down to power of 2
    entries = Integer.highestOneBit(entries);
    keys = new long[entries];
    data = new long[entries];
    mask = entries - 1;
}

def _recompute_zobrist(self) -> int:
    key = 0
    for sq in range(128):
        if _is_offboard(sq):
            continue
        piece = self.squares[sq]
        if piece:
            key ^= PIECE_SQUARE[piece_index(piece)][sq]
    key ^= CASTLING[self.castling_rights]
    if self.ep_square is not None:
        key ^= EP_FILE[self.ep_square & 7]
    if self.turn == BLACK:
        key ^= SIDE
    return key

