explicit TranspositionTable(std::size_t mb = 32) {
  std::size_t bytes = mb * 1024ULL * 1024ULL;
  std::size_t n = bytes / sizeof(TtEntry);
  if (n < 1024) {
    n = 1024;
  }
  std::size_t p2 = 1;
  while (p2 < n) {
    p2 <<= 1U;
  }
  entries_.resize(p2);
  mask_ = p2 - 1;
}
